  ['수평선', '---', /<hr>/],
  ['단락', 'Hello world', /<p>Hello world<\/p>/],
  ['XSS 방어', '<script>alert(1)</script>', /&lt;script&gt;/],
  ['이스케이프', '\\*not italic\\*', /\*not italic\*/],
];

let passed = 0, failed = 0;
for (const [name, input, pattern] of tests) {
  const result = MarkdownParser.parse(input);
  if (pattern.test(result)) {
    console.log(`✓ ${name}`);
