/**
 * 마크다운 파서 - 외부 라이브러리 없이 구현
 * 지원: 제목, 굵게/기울임, 인라인 코드, 코드 블록, 링크, 이미지,
 *       순서/비순서 목록(중첩), 인용구(중첩), 수평선, 단락, 줄바꿈, 이스케이프
 */

const MarkdownParser = (() => {
  // 이스케이프 가능한 특수문자 목록
  const ESCAPABLE = /\\([\\`*_{}\[\]()#+\-.!|])/g;

  // HTML 특수문자를 엔티티로 변환 (XSS 방지)
  function escapeHtml(text) {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  // 이스케이프 문자를 플레이스홀더로 치환 (파싱 중 보호)
  const escapeMap = new Map();
  let escapeCounter = 0;

  function protectEscapes(text) {
    escapeCounter = 0;
    escapeMap.clear();
    return text.replace(ESCAPABLE, (_, ch) => {
      const key = `\x00ESC${escapeCounter++}\x00`;
      escapeMap.set(key, escapeHtml(ch));
      return key;
    });
  }

  function restoreEscapes(text) {
    for (const [key, val] of escapeMap) {
      text = text.split(key).join(val);
    }
    return text;
  }

  // 인라인 요소 파싱 (굵게, 기울임, 인라인 코드, 링크, 이미지)
  function parseInline(text) {
    // 인라인 코드 블록 (백틱)을 먼저 보호
    const codeMap = new Map();
    let codeIdx = 0;
    text = text.replace(/(`+)([\s\S]*?)\1/g, (_, ticks, content) => {
      const key = `\x00CODE${codeIdx++}\x00`;
      codeMap.set(key, `<code>${escapeHtml(content)}</code>`);
      return key;
    });

    // 원시 HTML 이스케이프 (XSS 방지) — 인라인 코드 보호 후, 마크다운 패턴 처리 전
    text = text.replace(/&(?!(?:[a-zA-Z]+|#\d+|#x[0-9a-fA-F]+);)/g, '&amp;');
    text = text.replace(/</g, '&lt;').replace(/>/g, '&gt;');

    // 이미지 ![alt](url "title")
    text = text.replace(/!\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    });

    // 링크 [text](url "title")
    text = text.replace(/\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, linkText, href, title) => {
      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
      return `<a href="${escapeHtml(href)}"${titleAttr} target="_blank" rel="noopener">${parseInlineBasic(linkText)}</a>`;
    });

    // 굵게+기울임 ***text*** 또는 ___text___
    text = text.replace(/(\*{3}|_{3})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
      return `<strong><em>${parseInlineBasic(content)}</em></strong>`;
    });

    // 굵게 **text** 또는 __text__
    text = text.replace(/(\*{2}|_{2})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
      return `<strong>${parseInlineBasic(content)}</strong>`;
    });

    // 기울임 *text* 또는 _text_
    text = text.replace(/(\*|_)(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
      return `<em>${parseInlineBasic(content)}</em>`;
    });

    // 취소선 ~~text~~
    text = text.replace(/~~([\s\S]*?)~~/g, (_, content) => {
      return `<del>${content}</del>`;
    });

    // 줄바꿈: 줄 끝 공백 2개 또는 \
    text = text.replace(/  \n/g, '<br>\n');
    text = text.replace(/\\\n/g, '<br>\n');
    // 나머지 줄바꿈은 공백으로 (단락 내 연속 줄)
    text = text.replace(/\n/g, ' ');

    // 인라인 코드 복원
    for (const [key, val] of codeMap) {
      text = text.split(key).join(val);
    }

    return text;
  }

  // 재귀 없는 간단한 인라인 파싱 (링크 내부 텍스트 등에 사용)
  function parseInlineBasic(text) {
    text = text.replace(/(\*{3}|_{3})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong><em>${c}</em></strong>`);
    text = text.replace(/(\*{2}|_{2})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong>${c}</strong>`);
    text = text.replace(/(\*|_)(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<em>${c}</em>`);
    return text;
  }

  // 코드 블록 파싱 (펜스 코드 블록 ```lang ... ```)
  function parseCodeBlocks(text) {
    return text.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)^\1\s*$/gm, (_, fence, lang, code) => {
      const langClass = lang.trim() ? ` class="language-${escapeHtml(lang.trim())}"` : '';
      const langLabel = lang.trim() ? `<span class="code-lang">${escapeHtml(lang.trim())}</span>` : '';
      return `<div class="code-block-wrapper">${langLabel}<pre><code${langClass}>${escapeHtml(code)}</code></pre></div>`;
    });
  }

  // 목록 파싱 (순서/비순서, 중첩 지원)
  function parseLists(lines) {
    const result = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      // 비순서 목록 항목 감지
      const ulMatch = line.match(/^(\s*)[-*+]\s+(.*)/);
      // 순서 목록 항목 감지
      const olMatch = line.match(/^(\s*)\d+\.\s+(.*)/);

      if (ulMatch || olMatch) {
        const isOrdered = !!olMatch;
        const match = ulMatch || olMatch;
        const baseIndent = match[1].length;

        const items = [];
        while (i < lines.length) {
          const l = lines[i];
          const ulM = l.match(/^(\s*)[-*+]\s+(.*)/);
          const olM = l.match(/^(\s*)\d+\.\s+(.*)/);
          const m = ulM || olM;

          if (!m) break;

          const indent = m[1].length;
          if (indent < baseIndent) break;

          if (indent === baseIndent) {
            items.push({ indent, content: m[2], children: [] });
            i++;
          } else {
            // 중첩 항목: 이전 아이템의 children에 추가
            if (items.length > 0) {
              items[items.length - 1].children.push(l);
            }
            i++;
          }
        }

        const tag = isOrdered ? 'ol' : 'ul';
        const html = renderList(items, tag);
        result.push(html);
      } else {
        result.push(line);
        i++;
      }
    }

    return result;
  }

  function renderList(items, tag) {
    const listItems = items.map(item => {
      let content = parseInline(item.content);
      if (item.children.length > 0) {
        const childLines = item.children;
        const childResult = parseLists(childLines);
        // 중첩 목록 판단
        const firstChild = childLines[0] || '';
        const isChildOrdered = /^\s*\d+\.\s/.test(firstChild);
        content += '\n' + childResult.join('\n');
      }
      return `<li>${content}</li>`;
    });
    return `<${tag}>\n${listItems.join('\n')}\n</${tag}>`;
  }

  // 인용구 파싱 (중첩 지원)
  function parseBlockquotes(text) {
    // 단계별로 중첩 처리
    let prev = '';
    while (prev !== text) {
      prev = text;
      text = text.replace(/^((?:[ \t]*>[ \t]?.*\n?)+)/gm, (match) => {
        // > 를 하나씩 벗기기
        const inner = match.replace(/^[ \t]*>[ \t]?/gm, '');
        return `<blockquote>\n${parseBlockquotes(inner)}</blockquote>\n`;
      });
    }
    return text;
  }

  // 수평선 파싱
  function parseHorizontalRules(text) {
    return text.replace(/^[ \t]*([-*_])([ \t]*\1){2,}[ \t]*$/gm, '<hr>');
  }

  // 제목 파싱 (ATX 스타일)
  function parseHeadings(text) {
    return text.replace(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/gm, (_, hashes, content) => {
      const level = hashes.length;
      const id = content.toLowerCase().replace(/[^\w\s-]/g, '').replace(/\s+/g, '-');
      return `<h${level} id="${id}">${parseInline(content)}</h${level}>`;
    });
  }

  // 단락 파싱 (빈 줄로 구분)
  function parseParagraphs(blocks) {
    return blocks.map(block => {
      // 이미 블록 레벨 HTML 태그로 시작하면 그대로 반환
      if (/^<(h[1-6]|ul|ol|li|blockquote|pre|hr|div)[\s>]/.test(block.trim())) {
        return block;
      }
      if (block.trim() === '') return '';
      return `<p>${parseInline(block.trim())}</p>`;
    }).filter(b => b !== '');
  }

  // 메인 파싱 함수
  function parse(markdown) {
    if (!markdown) return '';

    // 이스케이프 문자 보호
    let text = protectEscapes(markdown);

    // 줄 끝 정규화
    text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

    // 1단계: 코드 블록 추출 및 보호 (파싱 중 내용 변환 방지)
    const codeBlockMap = new Map();
    let cbIdx = 0;
    text = text.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)^\1[ \t]*$/gm, (match, fence, lang, code) => {
      const key = `\x00CB${cbIdx++}\x00`;
      const langClass = lang.trim() ? ` class="language-${escapeHtml(lang.trim())}"` : '';
      const langLabel = lang.trim() ? `<span class="code-lang">${escapeHtml(lang.trim())}</span>` : '';
      codeBlockMap.set(key, `<div class="code-block-wrapper">${langLabel}<pre><code${langClass}>${escapeHtml(code)}</code></pre></div>`);
      return key;
    });

    // 2단계: 수평선 파싱
    text = parseHorizontalRules(text);

    // 3단계: 제목 파싱
    text = parseHeadings(text);

    // 4단계: 인용구 파싱
    text = parseBlockquotes(text);

    // 5단계: 목록 파싱 (줄 단위)
    const lines = text.split('\n');
    const processedLines = parseLists(lines);
    text = processedLines.join('\n');

    // 6단계: 코드 블록 복원
    for (const [key, val] of codeBlockMap) {
      text = text.split(key).join(val);
    }

    // 7단계: 빈 줄 기준으로 블록 분리 후 단락 처리
    const blocks = text.split(/\n{2,}/);
    const parsed = parseParagraphs(blocks);
    text = parsed.join('\n\n');

    // 8단계: 이스케이프 복원
    text = restoreEscapes(text);

    return text;
  }

  return { parse };
})();

/**
 * editor.test.js — 마크다운 에디터 종합 테스트
 * 외부 프레임워크 없이 console.log 기반 assertion 사용
 * 실행: node editor.test.js
 */

'use strict';

// ── 테스트 러너 ──────────────────────────────────────────────
let total = 0, passed = 0, failed = 0;
const failures = [];

function assert(condition, label, detail = '') {
  total++;
  if (condition) {
    passed++;
    console.log(`  ✓ ${label}`);
  } else {
    failed++;
    const msg = detail ? `${label} — ${detail}` : label;
    failures.push(msg);
    console.error(`  ✗ ${label}${detail ? '\n      ' + detail : ''}`);
  }
}

function assertMatch(str, pattern, label) {
  assert(pattern.test(str), label, `패턴 ${pattern} 에 매치 안 됨\n      출력: ${str.replace(/\n/g,' ').slice(0,120)}`);
}

function assertNoMatch(str, pattern, label) {
  assert(!pattern.test(str), label, `패턴 ${pattern} 가 있으면 안 됨\n      출력: ${str.replace(/\n/g,' ').slice(0,120)}`);
}

function assertEqual(a, b, label) {
  assert(a === b, label, `기대: ${JSON.stringify(b)}\n      실제: ${JSON.stringify(a)}`);
}

function section(name) {
  console.log(`\n${'─'.repeat(60)}`);
  console.log(`  ${name}`);
  console.log('─'.repeat(60));
}

// ── 환경 설정 ────────────────────────────────────────────────
// 파서 로드 (IIFE를 globalThis에 노출)
const fs = require('fs');
const parserSrc = fs.readFileSync('./markdown-parser.js', 'utf8')
  .replace('const MarkdownParser', 'globalThis.MarkdownParser');
eval(parserSrc);

// DOM/브라우저 API 모킹
const localStorageStore = {};
globalThis.localStorage = {
  getItem: (k) => localStorageStore[k] !== undefined ? localStorageStore[k] : null,
  setItem: (k, v) => { localStorageStore[k] = String(v); },
  removeItem: (k) => { delete localStorageStore[k]; },
  clear: () => { Object.keys(localStorageStore).forEach(k => delete localStorageStore[k]); },
};

// editor.js 에서 사용하는 DOM 요소 모킹
function makeElement(tag = 'div', extra = {}) {
  return Object.assign({
    tagName: tag.toUpperCase(),
    value: '',
    innerHTML: '',
    textContent: '',
    selectionStart: 0,
    selectionEnd: 0,
    className: '',
    dataset: {},
    style: {},
    children: [],
    _listeners: {},
    addEventListener(ev, fn) {
      if (!this._listeners[ev]) this._listeners[ev] = [];
      this._listeners[ev].push(fn);
    },
    dispatchEvent(ev) {
      const handlers = this._listeners[ev.type] || [];
      handlers.forEach(fn => fn(ev));
    },
    focus() {},
    click() {},
    querySelectorAll(sel) { return []; },
  }, extra);
}

// ────────────────────────────────────────────────────────────
// 1. 마크다운 파서 — 기본 요소
// ────────────────────────────────────────────────────────────
section('1. 파서 — 제목 (H1–H6)');
{
  const p = MarkdownParser.parse;
  for (let i = 1; i <= 6; i++) {
    const hashes = '#'.repeat(i);
    assertMatch(p(`${hashes} 제목${i}`), new RegExp(`<h${i}[^>]*>제목${i}</h${i}>`), `H${i} 제목`);
  }
  assertMatch(p('# 공백 포함 제목'), /<h1[^>]*>공백 포함 제목<\/h1>/, 'H1 공백 포함');
  assertMatch(p('## id 생성'), /id="id-/, 'H2 id 속성 생성');
}

section('2. 파서 — 인라인 서식');
{
  const p = MarkdownParser.parse;
  assertMatch(p('**굵게**'), /<strong>굵게<\/strong>/, '** 굵게');
  assertMatch(p('__굵게__'), /<strong>굵게<\/strong>/, '__ 굵게');
  assertMatch(p('*기울임*'), /<em>기울임<\/em>/, '* 기울임');
  assertMatch(p('_기울임_'), /<em>기울임<\/em>/, '_ 기울임');
  assertMatch(p('***굵+기울***'), /<strong><em>굵\+기울<\/em><\/strong>/, '*** 굵게+기울임');
  assertMatch(p('___굵+기울___'), /<strong><em>굵\+기울<\/em><\/strong>/, '___ 굵게+기울임');
  assertMatch(p('~~취소선~~'), /<del>취소선<\/del>/, '~~ 취소선');
  assertMatch(p('`인라인코드`'), /<code>인라인코드<\/code>/, '백틱 인라인 코드');
  assertMatch(p('``이중백틱``'), /<code>이중백틱<\/code>/, '이중 백틱 인라인 코드');
}

section('3. 파서 — 코드 블록');
{
  const p = MarkdownParser.parse;
  assertMatch(p('```\n코드\n```'), /code-block-wrapper/, '펜스 코드 블록');
  assertMatch(p('```js\nconsole.log()\n```'), /code-lang/, '언어 레이블 있는 코드 블록');
  assertMatch(p('```js\nconsole.log()\n```'), /language-js/, '언어 클래스 부여');
  assertMatch(p('```\n<b>태그</b>\n```'), /&lt;b&gt;태그&lt;\/b&gt;/, '코드 블록 내 HTML 이스케이프');
  assertMatch(p('~~~\n물결코드\n~~~'), /code-block-wrapper/, '물결선(~~~) 코드 블록');
  // 코드 블록 내부는 마크다운 처리 안 됨
  assertNoMatch(p('```\n**not bold**\n```'), /<strong>/, '코드 블록 내 마크다운 비처리');
}

section('4. 파서 — 링크 & 이미지');
{
  const p = MarkdownParser.parse;
  assertMatch(p('[텍스트](https://example.com)'), /<a href="https:\/\/example\.com"/, '기본 링크');
  assertMatch(p('[텍스트](https://example.com)'), /target="_blank"/, '링크 target=_blank');
  assertMatch(p('[텍스트](https://example.com "제목")'), /title="제목"/, '링크 title 속성');
  assertMatch(p('![대체텍스트](img.png)'), /<img src="img\.png" alt="대체텍스트">/, '기본 이미지');
  assertMatch(p('![alt](img.png "설명")'), /title="설명"/, '이미지 title 속성');
  // XSS 방어 — href에 javascript: 가 html 이스케이프 돼야 함
  assertNoMatch(p('[x](<script>)'), /<script>/, '링크 XSS 방어');
}

section('5. 파서 — 비순서 목록');
{
  const p = MarkdownParser.parse;
  assertMatch(p('- 항목1\n- 항목2'), /<ul>/, '- 비순서 목록');
  assertMatch(p('* 항목1\n* 항목2'), /<ul>/, '* 비순서 목록');
  assertMatch(p('+ 항목1\n+ 항목2'), /<ul>/, '+ 비순서 목록');
  assertMatch(p('- 항목1\n- 항목2'), /<li>항목1<\/li>/, '비순서 목록 항목 내용');
  // 중첩
  const nested = '- 상위\n  - 하위1\n  - 하위2';
  assertMatch(p(nested), /<ul>[\s\S]*<ul>/, '중첩 비순서 목록');
}

section('6. 파서 — 순서 목록');
{
  const p = MarkdownParser.parse;
  assertMatch(p('1. 첫째\n2. 둘째'), /<ol>/, '순서 목록');
  assertMatch(p('1. 첫째\n2. 둘째'), /<li>첫째<\/li>/, '순서 목록 항목 내용');
  // 중첩
  const nested = '1. 상위\n   1. 하위1\n   2. 하위2';
  assertMatch(p(nested), /<ol>[\s\S]*<ol>/, '중첩 순서 목록');
}

section('7. 파서 — 인용구');
{
  const p = MarkdownParser.parse;
  assertMatch(p('> 인용문'), /<blockquote>/, '기본 인용구');
  assertMatch(p('> 인용\n> 계속'), /<blockquote>/, '여러 줄 인용구');
  assertMatch(p('> 상위\n> > 하위'), /<blockquote>[\s\S]*<blockquote>/, '중첩 인용구');
}

section('8. 파서 — 수평선');
{
  const p = MarkdownParser.parse;
  assertMatch(p('---'), /<hr>/, '--- 수평선');
  assertMatch(p('***'), /<hr>/, '*** 수평선');
