    54→    text = text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
    55→
    56→    // 이미지 ![alt](url "title")
    57→    text = text.replace(/!\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
    58→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    59→      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    60→    });
    61→
    62→    // 링크 [text](url "title")
    63→    text = text.replace(/\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, linkText, href, title) => {
