   102→  // 재귀 없는 간단한 인라인 파싱 (링크 내부 텍스트 등에 사용)
   103→  function parseInlineBasic(text) {
   104→    text = text.replace(/(\*{3}|_{3})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong><em>${c}</em></strong>`);
   105→    text = text.replace(/(\*{2}|_{2})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong>${c}</strong>`);
   106→    text = text.replace(/(\*|_)(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<em>${c}</em>`);
