   187→  }
   188→
   189→  // 인용구 파싱 (중첩 지원)
   190→  function parseBlockquotes(text) {
   191→    // 단계별로 중첩 처리
   192→    let prev = '';
   193→    while (prev !== text) {
   194→      prev = text;
   195→      text = text.replace(/^((?:[ \t]*>[ \t]?.*\n?)+)/gm, (match) => {
   196→        // > 를 하나씩 벗기기
   197→        const inner = match.replace(/^[ \t]*>[ \t]?/gm, '');
   198→        const processed = parseBlockquotes(inner);
   199→        // 인라인 서식 적용 (이미 HTML 태그로 시작하는 줄은 건너뜀)
   200→        const withInline = processed.replace(/^(?!<\w)(.+)$/gm, (line) => parseInline(line));
   201→        return `<blockquote>\n${withInline}</blockquote>\n`;
   202→      });
   203→    }
   204→    return text;
   205→  }
   206→
   207→  // 수평선 파싱
   208→  function parseHorizontalRules(text) {
   209→    return text.replace(/^[ \t]*([-*_])([ \t]*\1){2,}[ \t]*$/gm, '<hr>');
   210→  }
   211→
   212→  // 제목 파싱 (ATX 스타일)
   213→  function parseHeadings(text) {
   214→    return text.replace(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/gm, (_, hashes, content) => {
   215→      const level = hashes.length;
   216→      const id = content.toLowerCase().replace(/[^\w\s-]/g, '').replace(/\s+/g, '-');
   217→      return `<h${level} id="${id}">${parseInline(content)}</h${level}>`;
   218→    });
   219→  }
   220→
   221→  // 단락 파싱 (빈 줄로 구분)
   222→  function parseParagraphs(blocks) {
   223→    return blocks.map(block => {
   224→      // 이미 블록 레벨 HTML 태그로 시작하면 그대로 반환
   225→      if (/^<(h[1-6]|ul|ol|li|blockquote|pre|hr|div)[\s>]/.test(block.trim())) {
   226→        return block;
   227→      }
   228→      if (block.trim() === '') return '';
   229→      return `<p>${parseInline(block.trim())}</p>`;
   230→    }).filter(b => b !== '');
   231→  }
   232→
   233→  // 메인 파싱 함수
   234→  function parse(markdown) {
   235→    if (!markdown) return '';
   236→
   237→    // 이스케이프 문자 보호
   238→    let text = protectEscapes(markdown);
   239→
   240→    // 줄 끝 정규화
   241→    text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
   242→
   243→    // 1단계: 코드 블록 추출 및 보호 (파싱 중 내용 변환 방지)
   244→    const codeBlockMap = new Map();
   245→    let cbIdx = 0;
   246→    text = text.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)^\1[ \t]*$/gm, (match, fence, lang, code) => {
   247→      const key = `\x00CB${cbIdx++}\x00`;
   248→      const langClass = lang.trim() ? ` class="language-${escapeHtml(lang.trim())}"` : '';
   249→      const langLabel = lang.trim() ? `<span class="code-lang">${escapeHtml(lang.trim())}</span>` : '';
   250→      codeBlockMap.set(key, `<div class="code-block-wrapper">${langLabel}<pre><code${langClass}>${escapeHtml(code)}</code></pre></div>`);
   251→      return key;
   252→    });
   253→
   254→    // 2단계: 수평선 파싱
   255→    text = parseHorizontalRules(text);
   256→
   257→    // 3단계: 제목 파싱
   258→    text = parseHeadings(text);
   259→
   260→    // 4단계: 인용구 파싱
   261→    text = parseBlockquotes(text);
   262→
   263→    // 5단계: 목록 파싱 (줄 단위)
   264→    const lines = text.split('\n');
   265→    const processedLines = parseLists(lines);
   266→    text = processedLines.join('\n');
   267→
   268→    // 6단계: 코드 블록 복원
   269→    for (const [key, val] of codeBlockMap) {
   270→      text = text.split(key).join(val);
   271→    }
   272→
   273→    // 7단계: 빈 줄 기준으로 블록 분리 후 단락 처리
   274→    const blocks = text.split(/\n{2,}/);
   275→    const parsed = parseParagraphs(blocks);
   276→    text = parsed.join('\n\n');
   277→
   278→    // 8단계: 이스케이프 복원
   279→    text = restoreEscapes(text);
   280→
   281→    return text;
   282→  }
   283→
   284→  return { parse };
   285→})();
