    h1:         () => insertLinePrefix('# '),
    h2:         () => insertLinePrefix('## '),
    h3:         () => insertLinePrefix('### '),
    link:       () => insertLink(),
    image:      () => insertImage(),
    code:       () => insertCodeBlock(),
    ul:         () => insertLinePrefix('- '),
    ol:         () => insertOrderedList(),
    blockquote: () => insertLinePrefix('> '),
    hr:         () => insertAtCursor('\n---\n'),
    export:     () => exportHtml(),
  };

  function insertLink() {
    const start = editor.selectionStart;
    const end   = editor.selectionEnd;
    const selected = editor.value.slice(start, end);
    if (selected) {
      wrapSelection('[', '](https://)', selected);
      // 커서를 URL 위치로 이동
      const newPos = start + 1 + selected.length + 2;
      editor.selectionStart = newPos;
      editor.selectionEnd   = newPos + 8; // "https://" 선택
    } else {
      wrapSelection('[링크 텍스트](https://)');
    }
    editor.focus();
  }

  function insertImage() {
    const start = editor.selectionStart;
    const end   = editor.selectionEnd;
    const selected = editor.value.slice(start, end);
    const alt = selected || '이미지 설명';
    wrapSelection(`![${alt}](`, ')', '이미지 URL');
    editor.focus();
  }

  function insertCodeBlock() {
    const start    = editor.selectionStart;
    const end      = editor.selectionEnd;
    const selected = editor.value.slice(start, end);
    const val      = editor.value;

    if (selected.includes('\n')) {
      // 여러 줄 선택 → 코드 블록
      const block = '```\n' + selected + '\n```';
      editor.value = val.slice(0, start) + block + val.slice(end);
      editor.selectionStart = start + 4;
      editor.selectionEnd   = start + 4 + selected.length;
    } else if (selected) {
      // 단일 줄 선택 → 인라인 코드
      wrapSelection('`', '`', selected);
      return;
    } else {
      // 선택 없음 → 코드 블록 삽입
      const block = '```\n코드를 입력하세요\n```';
      editor.value = val.slice(0, start) + block + val.slice(end);
      editor.selectionStart = start + 4;
      editor.selectionEnd   = start + 4 + 11;
    }
    editor.focus();
    editor.dispatchEvent(new Event('input'));
  }

  function insertOrderedList() {
    const start = editor.selectionStart;
    const end   = editor.selectionEnd;
    const val   = editor.value;
    const selected = val.slice(start, end);

    if (selected) {
      const lines = selected.split('\n');
      const numbered = lines.map((l, i) => `${i + 1}. ${l}`).join('\n');
      editor.value = val.slice(0, start) + numbered + val.slice(end);
      editor.selectionStart = start;
      editor.selectionEnd   = start + numbered.length;
    } else {
      insertLinePrefix('1. ');
      return;
    }
    editor.focus();
    editor.dispatchEvent(new Event('input'));
  }

  // ── 툴바 버튼 바인딩 ───────────────────────────────────────
  function bindToolbar() {
    document.querySelectorAll('[data-action]').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.preventDefault();
        const action = btn.dataset.action;
        if (ACTIONS[action]) ACTIONS[action]();
      });
    });
  }

  // ── 키보드 단축키 ──────────────────────────────────────────
  function bindKeyboardShortcuts() {
    editor.addEventListener('keydown', (e) => {
      const ctrl = e.ctrlKey || e.metaKey;
      if (!ctrl) return;

      switch (e.key.toLowerCase()) {
