      editorPane.style.width = newWidth + 'px';
    }, { passive: true });

    document.addEventListener('touchend', () => {
      if (!isResizing) return;
      isResizing = false;
      resizer.classList.remove('dragging');
      editorArea.classList.remove('resizing');
    });
  }

